import{_ as e,o as a,c as r,ag as i}from"./chunks/framework.OsDJF_Ea.js";const m=JSON.parse('{"title":"Drum Machine Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"guides/drum-machine.md","filePath":"guides/drum-machine.md"}'),o={name:"guides/drum-machine.md"};function n(d,t,l,h,c,s){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="drum-machine-workflow" tabindex="-1">Drum Machine Workflow <a class="header-anchor" href="#drum-machine-workflow" aria-label="Permalink to &quot;Drum Machine Workflow&quot;">​</a></h1><p>The <strong>Drum Machine</strong> module is a 4-voice drum synthesizer with kick, snare, hi-hat, and percussion voices. Each voice is fully tuneable with layered sound design.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><ol><li>Add a <strong>Drum Machine</strong> module -- it auto-maps to 2 banks</li><li>Add a <strong>Stereo Out</strong> and connect the drum machine&#39;s mix outputs</li><li>Upload the patch</li><li>Press buttons 1-4 to trigger each voice (bank 1)</li></ol><h2 id="hardware-controls" tabindex="-1">Hardware Controls <a class="header-anchor" href="#hardware-controls" aria-label="Permalink to &quot;Hardware Controls&quot;">​</a></h2><h3 id="bank-1-trigger-and-pitch" tabindex="-1">Bank 1: Trigger and Pitch <a class="header-anchor" href="#bank-1-trigger-and-pitch" aria-label="Permalink to &quot;Bank 1: Trigger and Pitch&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Control</th><th>Function</th></tr></thead><tbody><tr><td>Pot 1</td><td>Kick pitch</td></tr><tr><td>Pot 2</td><td>Snare pitch</td></tr><tr><td>Pot 3</td><td>Hi-hat frequency</td></tr><tr><td>Pot 4</td><td>Percussion pitch</td></tr><tr><td>Buttons 1-4</td><td>Trigger kick, snare, hat, perc</td></tr></tbody></table><h3 id="bank-2-volume-and-mute" tabindex="-1">Bank 2: Volume and Mute <a class="header-anchor" href="#bank-2-volume-and-mute" aria-label="Permalink to &quot;Bank 2: Volume and Mute&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Control</th><th>Function</th></tr></thead><tbody><tr><td>Pot 1</td><td>Kick volume</td></tr><tr><td>Pot 2</td><td>Snare volume</td></tr><tr><td>Pot 3</td><td>Hi-hat volume</td></tr><tr><td>Pot 4</td><td>Percussion volume</td></tr><tr><td>Buttons 1-4</td><td>Mute kick, snare, hat, perc</td></tr></tbody></table><h2 id="editing-voices" tabindex="-1">Editing Voices <a class="header-anchor" href="#editing-voices" aria-label="Permalink to &quot;Editing Voices&quot;">​</a></h2><p>Click the Drum Machine module title in the patcher to open the <strong>Drum Designer</strong>. Each voice has parameters for:</p><ul><li>Tone pitch and sweep</li><li>Noise character and filtering</li><li>Amplitude envelope (attack, decay, sustain, release)</li><li>Output gain and aux send level</li></ul><h2 id="sequencing" tabindex="-1">Sequencing <a class="header-anchor" href="#sequencing" aria-label="Permalink to &quot;Sequencing&quot;">​</a></h2><p>Connect a <strong>Clocks</strong> module to the drum machine&#39;s gate inputs for programmed rhythms. The Clocks module provides multiple divided/multiplied clock outputs with probability and swing.</p>',14)])])}const p=e(o,[["render",n]]);export{m as __pageData,p as default};
